import{_ as t,o as l,c as i,ag as e}from"./chunks/framework.DXGyWiRo.js";const q=JSON.parse('{"title":"1994年巴菲特致股东信核心要点","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1994年/核心总结.md","filePath":"01_letters/1994年/核心总结.md"}'),o={name:"01_letters/1994年/核心总结.md"};function r(h,a,d,u,n,s){return l(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="_1994年巴菲特致股东信核心要点" tabindex="-1">1994年巴菲特致股东信核心要点 <a class="header-anchor" href="#_1994年巴菲特致股东信核心要点" aria-label="Permalink to &quot;1994年巴菲特致股东信核心要点&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增长13.9%</li><li>每股账面价值增长13.9%（从$19增长至$10,083）</li><li>31年复合增长率：23%</li></ul><h2 id="核心投资哲学" tabindex="-1">核心投资哲学 <a class="header-anchor" href="#核心投资哲学" aria-label="Permalink to &quot;核心投资哲学&quot;">​</a></h2><h3 id="_1-肥胖钱包是卓越投资成果的敌人" tabindex="-1">1. &quot;肥胖钱包是卓越投资成果的敌人&quot; <a class="header-anchor" href="#_1-肥胖钱包是卓越投资成果的敌人" aria-label="Permalink to &quot;1. &quot;肥胖钱包是卓越投资成果的敌人&quot;&quot;">​</a></h3><ul><li>伯克希尔净资产已达119亿美元</li><li>需要至少1亿美元的投资机会才能产生影响</li><li>投资范围大幅缩小</li></ul><h3 id="_2-投资策略" tabindex="-1">2. 投资策略 <a class="header-anchor" href="#_2-投资策略" aria-label="Permalink to &quot;2. 投资策略&quot;">​</a></h3><ul><li>忽略政治和经济预测</li><li>投资那些业务简单、长期前景确定的企业</li><li>等待&quot;甜蜜区&quot;的好球</li></ul><h3 id="_3-本·格雷厄姆的遗产" tabindex="-1">3. 本·格雷厄姆的遗产 <a class="header-anchor" href="#_3-本·格雷厄姆的遗产" aria-label="Permalink to &quot;3. 本·格雷厄姆的遗产&quot;">​</a></h3><ul><li>投资原则在重大事件中经受了考验</li><li>恐惧是投机者的敌人，是价值投资者的朋友</li></ul><hr><h2 id="_1994年收购" tabindex="-1">1994年收购 <a class="header-anchor" href="#_1994年收购" aria-label="Permalink to &quot;1994年收购&quot;">​</a></h2><h3 id="斯斯科特·费泽制造集团-scott-fetzer" tabindex="-1">斯斯科特·费泽制造集团（Scott Fetzer） <a class="header-anchor" href="#斯斯科特·费泽制造集团-scott-fetzer" aria-label="Permalink to &quot;斯斯科特·费泽制造集团（Scott Fetzer）&quot;">​</a></h3><ul><li>1986年收购，1994年ROE在《财富》500强中排名第4</li><li>拉尔夫·谢伊（Ralph Schey）的杰出管理</li><li>关键：专注于基本业务，不分散注意力</li></ul><h3 id="会计教训" tabindex="-1">会计教训 <a class="header-anchor" href="#会计教训" aria-label="Permalink to &quot;会计教训&quot;">​</a></h3><ul><li>收购溢价$142.6M，需要多年摊销</li><li>账面价值与内在价值可能大幅偏离</li></ul><hr><h2 id="股票投资策略" tabindex="-1">股票投资策略 <a class="header-anchor" href="#股票投资策略" aria-label="Permalink to &quot;股票投资策略&quot;">​</a></h2><h3 id="投资四原则" tabindex="-1">投资四原则 <a class="header-anchor" href="#投资四原则" aria-label="Permalink to &quot;投资四原则&quot;">​</a></h3><ol><li>可理解的企业</li><li>良好的长期前景</li><li>诚实且有能力的管理层</li><li>有吸引力的价格</li></ol><h3 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h3><blockquote><p>&quot;在投资中，不需要做非凡的事情来获得非凡的结果。&quot;</p></blockquote><blockquote><p>&quot;对于投资者来说，不需要知道男人的确切年龄就知道他够老到可以投票，也不需要知道他的确切体重就能知道他需要节食。&quot;</p></blockquote><hr><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="浮存金数据-1994" tabindex="-1">浮存金数据（1994） <a class="header-anchor" href="#浮存金数据-1994" aria-label="Permalink to &quot;浮存金数据（1994）&quot;">​</a></h3><ul><li>平均浮存金：$3,056.6M</li><li>资金成本：负（盈利）</li><li>1967-1994年：27年中有20年浮存金成本为负</li></ul><h3 id="超级巨灾保险" tabindex="-1">超级巨灾保险 <a class="header-anchor" href="#超级巨灾保险" aria-label="Permalink to &quot;超级巨灾保险&quot;">​</a></h3><ul><li>1994年盈利</li><li>阿吉特·贾恩（Ajit Jain）是行业最佳</li><li>最坏情况损失：$600M（税后）</li></ul><hr><h2 id="普通股持仓-1994年底" tabindex="-1">普通股持仓（1994年底） <a class="header-anchor" href="#普通股持仓-1994年底" aria-label="Permalink to &quot;普通股持仓（1994年底）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>持股</th><th>成本</th><th>市值</th></tr></thead><tbody><tr><td>可口可乐</td><td>100M股</td><td>$1,299M</td><td>$5,150M</td></tr><tr><td>大都会/ABC</td><td>20M股</td><td>$345M</td><td>$1,705M</td></tr><tr><td>政府雇员保险</td><td>34.25M股</td><td>$46M</td><td>$1,678M</td></tr><tr><td>吉列</td><td>24M股</td><td>$600M</td><td>$1,797M</td></tr><tr><td>富国银行</td><td>6.79M股</td><td>$424M</td><td>$985M</td></tr></tbody></table><hr><h2 id="错误教训" tabindex="-1">错误教训 <a class="header-anchor" href="#错误教训" aria-label="Permalink to &quot;错误教训&quot;">​</a></h2><h3 id="_1-出售capital-cities" tabindex="-1">1. 出售Capital Cities <a class="header-anchor" href="#_1-出售capital-cities" aria-label="Permalink to &quot;1. 出售Capital Cities&quot;">​</a></h3><ul><li>1993年以$63出售1000万股</li><li>1994年底价格：$85.25</li><li>损失：$2.225亿</li></ul><h3 id="_2-usair投资" tabindex="-1">2. USAir投资 <a class="header-anchor" href="#_2-usair投资" aria-label="Permalink to &quot;2. USAir投资&quot;">​</a></h3><ul><li>1989年投资$358M</li><li>1994年减记75%，只剩$89.5M</li><li>航空业成本结构问题导致巨额亏损</li></ul><hr><h2 id="经典语录-1" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录-1" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><ol><li><p><strong>关于市场预测</strong>：</p><blockquote><p>&quot;我们将继续忽视政治和经济预测，这对许多投资者和商人来说是昂贵的干扰。&quot;</p></blockquote></li><li><p><strong>关于投资机会</strong>：</p><blockquote><p>&quot;特德·威廉姆斯：如果我必须去咬我甜蜜区外的球，我可能只有.250的打击率，而不是.344。&quot;</p></blockquote></li><li><p><strong>关于能力圈</strong>：</p><blockquote><p>&quot;一个投资者只需要做对很少的事情，只要他或她避免犯大错误。&quot;</p></blockquote></li><li><p><strong>关于恐惧与贪婪</strong>：</p><blockquote><p>&quot;恐惧是投机者的敌人，但是价值投资者的朋友。&quot;</p></blockquote></li></ol><hr><h2 id="内在价值与账面价值" tabindex="-1">内在价值与账面价值 <a class="header-anchor" href="#内在价值与账面价值" aria-label="Permalink to &quot;内在价值与账面价值&quot;">​</a></h2><ul><li>1964年：账面价值$19.46，但内在价值更低（纺织业务拖累）</li><li>现在：账面价值大幅低估内在价值</li><li>内在价值 = 企业剩余寿命期间预期现金流的折现值</li></ul><hr><h2 id="_1994年启示" tabindex="-1">1994年启示 <a class="header-anchor" href="#_1994年启示" aria-label="Permalink to &quot;1994年启示&quot;">​</a></h2><ol><li><strong>规模是业绩的敌人</strong>：资金量越大，超越市场的难度越高</li><li><strong>坚守能力圈</strong>：等待真正的好机会</li><li><strong>忽略短期波动</strong>：关注企业长期价值</li><li><strong>选择优秀管理层</strong>：这是企业成功的关键</li><li><strong>避免杠杆</strong>：不借钱投资</li></ol>',47)])])}const b=t(o,[["render",r]]);export{q as __pageData,b as default};
